class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int left = 1, right = n;
        int ans = 0;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (canReduce(nums, maxC, mid)) {
                ans = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return ans;
    }

    private boolean canReduce(int[] nums, int maxC, int target) {
        int n = nums.length;
        int[] dp = new int[n + 1];
        for (int d = 2; d <= 100; d++) {
            int cnt = 0;
            for (int i = 0; i < n; i++) {
                if (nums[i] % d != 0) cnt++;
                dp[i + 1] = Math.min(dp[i] + (nums[i] % d != 0 ? 1 : 0), cnt);
                if (i + 1 >= target) {
                    if (dp[i + 1] - dp[i + 1 - target] <= maxC) return true;
                }
            }
        }
        return false;
    }
}
